const emailItem = $('Gmail Trigger').first();

const subject = emailItem.json.Subject || emailItem.json.subject || '';
const body = emailItem.json.snippet || emailItem.json.textPlain || emailItem.json.textHtml || '';
const fullText = subject + ' ' + body;

const phoneMatch = fullText.match(/llamado[\s\S]{0,10}?34\s*(\d[\s\d]{7,11})/i);
let phone = null;
if (phoneMatch) {
  const digits = phoneMatch[1].replace(/\s/g, '');
  phone = '+34' + digits.slice(0, 9);
}

let status = 'desconocido';
const statusMatch = fullText.match(/Estado[\s\S]{0,5}?(atendida|no contestada)/i);
if (statusMatch) status = statusMatch[1].toLowerCase();

const durationMatch = fullText.match(/segundos[\s\S]{0,5}?(\d+)/i);
const duration = durationMatch ? parseInt(durationMatch[1]) : null;

const adCodeMatch = fullText.match(/anuncio[\s\S]{0,10}?(\d{6,})/i);
const adCode = adCodeMatch ? adCodeMatch[1] : null;

const roomMatch = fullText.match(/Ref\.?\s*(\d{1,2}H\d*)/i);
const room = roomMatch ? roomMatch[1].toUpperCase() : null;

const receivedAt = emailItem.json.internalDate
  ? new Date(parseInt(emailItem.json.internalDate)).toISOString()
  : new Date().toISOString();

return [{ json: { phone, status, room, adCode, subject, duration, emailId: emailItem.json.id, receivedAt, hasPhone: !!phone } }];

const roomsData = $input.first().json;
const extractData = $('Extraer Datos').first().json;
const rooms = roomsData.rooms || [];
const room = extractData.room;
const adCode = extractData.adCode;

// Find room: first by SKU (Ref. in email), then by Idealista ad code in URL
let roomInfo = null;
if (room) {
  roomInfo = rooms.find(r => r.sku && r.sku.toUpperCase() === room.toUpperCase());
}
if (!roomInfo && adCode) {
  roomInfo = rooms.find(r => {
    const idealistaUrl = r.marketplace_links?.idealista || '';
    return idealistaUrl.includes(adCode);
  });
}

const resolvedRoom = roomInfo?.sku || room || null;

let primerMensaje;
if (roomInfo) {
  const precio = roomInfo.price ? `${roomInfo.price}€/mes` : '';
  const city = roomInfo.city || '';
  const addressPart = roomInfo.address ? roomInfo.address.split(',')[0] : '';
  primerMensaje = `Hola! Vi que llamaste por la habitación *${resolvedRoom}* en Idealista\n\nEstá en ${addressPart}, ${city}${precio ? ` — ${precio}` : ''}.\n\n¿Te puedo dar más información? Dime qué buscas y te ayudo`;
} else {
  primerMensaje = `Hola! Vi que llamaste por una de nuestras habitaciones en Idealista\n\n¿Cuál te había llamado la atención? Puedes pasarme la URL del anuncio o el código de referencia y te cuento todo`;
}

const customFields = [
  { id: 'nlwW6ZwJyz2r9uu38dhK', field_value: 'ON' },
  { id: 'Im3eq9FwmOYF3uOQMBD1', field_value: 'No' }
];
if (resolvedRoom) customFields.push({ id: '5A0P645BNNFYi7HSSOow', field_value: resolvedRoom });
if (roomInfo?.price) customFields.push({ id: 'ZOc55lLvxodtdqLE2nGV', field_value: String(roomInfo.price) });
if (roomInfo?.listing_url) customFields.push({ id: 'aJ0p8495oKcMJbgSiKTL', field_value: roomInfo.listing_url });

return [{
  json: {
    phone: extractData.phone,
    room: resolvedRoom,
    adCode, status: extractData.status,
    emailId: extractData.emailId, receivedAt: extractData.receivedAt,
    primerMensaje, customFields,
    roomInfo: roomInfo ? { precio: roomInfo.price, ciudad: roomInfo.city, direccion: roomInfo.address, listingUrl: roomInfo.listing_url } : null
  }
}];

