const searchResult = $input.first().json;
const preparar = $('Preparar Datos').first().json;

const contacts = searchResult.contacts || [];
const existing = contacts.length > 0 ? contacts[0] : null;

// Use existing name or fallback to Llamada Idealista + date/time
let firstName, lastName;
if (existing && (existing.firstName || existing.lastName)) {
  firstName = existing.firstName || 'Llamada Idealista';
  lastName = existing.lastName || '';
} else {
  const dt = new Date(preparar.receivedAt);
  const fecha = dt.toLocaleDateString('es-ES', { day: '2-digit', month: '2-digit', year: 'numeric' });
  const hora = dt.toLocaleTimeString('es-ES', { hour: '2-digit', minute: '2-digit', timeZone: 'Europe/Madrid' });
  firstName = 'Llamada Idealista';
  lastName = `${fecha} ${hora}${preparar.room ? ' — ' + preparar.room : ''}${preparar.roomInfo?.precio ? ' ' + preparar.roomInfo.precio + '€' : ''}${preparar.roomInfo?.direccion ? ' ' + preparar.roomInfo.direccion.split(',')[0] : ''}`;
}

return [{
  json: {
    ...preparar,
    firstName,
    lastName,
    existingContactId: existing?.id || null
  }
}];

// Dedup: skip if same phone was messaged in last 5 minutes
const phone = $('Preparar Datos').first().json.phone;
const staticData = $getWorkflowStaticData('global');

if (!staticData.sentPhones) staticData.sentPhones = {};

const now = Date.now();
const lastSent = staticData.sentPhones[phone];
const FIVE_MIN = 5 * 60 * 1000;

// Clean old entries (>10 min) to avoid memory buildup
for (const [p, ts] of Object.entries(staticData.sentPhones)) {
  if (now - ts > FIVE_MIN * 2) delete staticData.sentPhones[p];
}

if (lastSent && (now - lastSent) < FIVE_MIN) {
  // Already sent to this phone recently — skip
  return [];
}

// Record this send
staticData.sentPhones[phone] = now;

// Pass through
return $input.all();

